import {
  collection,
  deleteDoc,
  doc,
  getDoc,
  getDocs,
  query,
  where,
  writeBatch
} from 'firebase/firestore'
import { db, COLLECTIONS } from './firebase'

export interface DeleteCompanyResult {
  companyId: string
  deletedByCollection: Record<string, number>
  totalDeleted: number
  warnings: string[]
}

const BATCH_LIMIT = 450

const COMPANY_FILTER_COLLECTIONS: string[] = [
  COLLECTIONS.USERS,
  COLLECTIONS.SUBSCRIPTIONS,
  COLLECTIONS.BILLING_RECORDS,
  COLLECTIONS.SETTINGS,
  COLLECTIONS.BUSINESSES,
  COLLECTIONS.INVOICES,
  `${COLLECTIONS.INVOICES}_payments`,
  COLLECTIONS.PARTIES,
  `${COLLECTIONS.PARTIES}_ledger`,
  COLLECTIONS.ITEMS,
  COLLECTIONS.EXPENSES,
  COLLECTIONS.QUOTATIONS,
  COLLECTIONS.PAYMENTS_IN,
  COLLECTIONS.PAYMENTS_OUT,
  COLLECTIONS.BANKING,
  COLLECTIONS.CREDIT_NOTES,
  COLLECTIONS.DEBIT_NOTES,
  COLLECTIONS.DELIVERY_CHALLANS,
  COLLECTIONS.PURCHASE_ORDERS,
  COLLECTIONS.PROFORMA_INVOICES,
  COLLECTIONS.EWAY_BILLS,
  COLLECTIONS.PRICE_LISTS,
  COLLECTIONS.STAFF_MASTER,
  COLLECTIONS.CRM_LEADS,
  COLLECTIONS.CRM_ACTIVITIES,
  COLLECTIONS.CRM_SITE_VISITS,
  COLLECTIONS.CRM_REQUIREMENTS,
  COLLECTIONS.CRM_DRAWINGS,
  COLLECTIONS.CRM_QUOTATIONS,
  COLLECTIONS.CRM_ATTACHMENTS,
  COLLECTIONS.CRM_AUDIT_LOGS,
  COLLECTIONS.CRM_SETTINGS,
  'user_permissions'
]

const COMPANY_DIRECT_DOC_COLLECTIONS: string[] = [
  COLLECTIONS.SUBSCRIPTIONS,
  COLLECTIONS.SETTINGS,
  COLLECTIONS.BUSINESSES
]

const deleteByCompanyId = async (collectionName: string, companyId: string): Promise<number> => {
  if (!db) {
    throw new Error('Firebase not initialized')
  }

  const colRef = collection(db, collectionName)
  const snapshot = await getDocs(query(colRef, where('companyId', '==', companyId)))
  if (snapshot.empty) return 0

  let deleted = 0
  let batch = writeBatch(db)
  let batchCount = 0

  for (const docSnap of snapshot.docs) {
    batch.delete(doc(db, collectionName, docSnap.id))
    batchCount++
    deleted++

    if (batchCount >= BATCH_LIMIT) {
      await batch.commit()
      batch = writeBatch(db)
      batchCount = 0
    }
  }

  if (batchCount > 0) {
    await batch.commit()
  }

  return deleted
}

const deleteDirectCompanyDoc = async (collectionName: string, companyId: string): Promise<number> => {
  if (!db) {
    throw new Error('Firebase not initialized')
  }

  const directRef = doc(db, collectionName, companyId)
  const directSnap = await getDoc(directRef)
  if (!directSnap.exists()) return 0

  await deleteDoc(directRef)
  return 1
}

export const deleteCompanyData = async (companyId: string): Promise<DeleteCompanyResult> => {
  if (!companyId?.trim()) {
    throw new Error('Company ID is required')
  }
  if (!db) {
    throw new Error('Firebase not initialized')
  }

  const deletedByCollection: Record<string, number> = {}
  const warnings: string[] = []
  let totalDeleted = 0

  for (const collectionName of COMPANY_DIRECT_DOC_COLLECTIONS) {
    try {
      const deleted = await deleteDirectCompanyDoc(collectionName, companyId)
      if (deleted > 0) {
        deletedByCollection[collectionName] = (deletedByCollection[collectionName] || 0) + deleted
        totalDeleted += deleted
      }
    } catch (error: any) {
      warnings.push(`${collectionName}: ${error?.message || 'unknown error'}`)
    }
  }

  for (const collectionName of COMPANY_FILTER_COLLECTIONS) {
    try {
      const deleted = await deleteByCompanyId(collectionName, companyId)
      if (deleted > 0) {
        deletedByCollection[collectionName] = (deletedByCollection[collectionName] || 0) + deleted
        totalDeleted += deleted
      }
    } catch (error: any) {
      warnings.push(`${collectionName}: ${error?.message || 'unknown error'}`)
    }
  }

  if (totalDeleted === 0 && warnings.length > 0) {
    throw new Error(`Delete failed for "${companyId}". ${warnings[0]}`)
  }

  return {
    companyId,
    deletedByCollection,
    totalDeleted,
    warnings
  }
}

